<?php
declare(strict_types=1);require __DIR__.'/bootstrap.php';$token=trim((string)($_GET['token']??$_POST['token']??''));$error='';$complete=false;
if(vp3_method()==='POST'){vp3_verify_csrf();$password=(string)($_POST['password']??'');$confirm=(string)($_POST['confirm_password']??'');if(strlen($password)<12||$password!==$confirm)$error='Use matching passwords of at least 12 characters.';elseif(!vp3_db_available())$error='Database configuration is required.';else{$hash=vp3_hash_token($token);$complete=vp3_transaction(function(PDO $db)use($hash,$password):bool{$stmt=$db->prepare('SELECT id,viewer_id FROM viewer_password_resets WHERE token_hash=? AND used_at IS NULL AND expires_at>NOW() LIMIT 1 FOR UPDATE');$stmt->execute([$hash]);$row=$stmt->fetch();if(!is_array($row))return false;$db->prepare('UPDATE viewer_password_resets SET used_at=NOW() WHERE id=?')->execute([(int)$row['id']]);$db->prepare('UPDATE viewer_accounts SET password_hash=?,updated_at=NOW() WHERE id=?')->execute([password_hash($password,PASSWORD_DEFAULT),(int)$row['viewer_id']]);$db->prepare('DELETE FROM viewer_remember_tokens WHERE viewer_id=?')->execute([(int)$row['viewer_id']]);return true;});if(!$complete)$error='This reset link is expired or already used.';}}
$pageTitle='Reset Viewer Password';$bodyClass='auth-page viewer-auth-page';$extraStyles=['assets/css/reels.css'];require VP3_ROOT.'/includes/header.php';?>
<section class="auth-layout compact-auth"><div class="auth-panel"><div class="auth-panel-inner"><span class="eyebrow">Viewer recovery</span><h1><?=$complete?'Password updated.':'Choose a new password.'?></h1><?php if($complete):?><a class="button auth-submit" href="viewer-login.php">Viewer sign in</a><?php else:?><?php if($error):?><div class="flash error"><?=vp3_e($error)?></div><?php endif;?><form method="post"><?=vp3_csrf_field()?><input type="hidden" name="token" value="<?=vp3_e($token)?>"><div class="field"><label>New password<input type="password" name="password" minlength="12" required></label></div><div class="field"><label>Confirm password<input type="password" name="confirm_password" minlength="12" required></label></div><button class="button auth-submit">Update password</button></form><?php endif;?></div></div></section>
